  media_library = jsonb_set(
    COALESCE(e.media_library, '{}'::jsonb),
    '{clinical_or_sport_science_references}',
    COALESCE(
      (
        SELECT jsonb_agg(elem ORDER BY elem)
        FROM (
          SELECT DISTINCT elem
          FROM (
            SELECT jsonb_array_elements_text(
              COALESCE(e.media_library->'clinical_or_sport_science_references', '[]'::jsonb)
            ) AS elem
            UNION ALL
            SELECT unnest(ARRAY['https://www.youtube.com/watch?v=LXIWCJqsYBo', 'https://www.youtube.com/watch?v=4EPsl0epycc', 'https://www.youtube.com/watch?v=7VQU2-yFZME', 'https://www.youtube.com/watch?v=Cn43k8-7iik', 'https://www.youtube.com/watch?v=Q4fKfxG33sY']::text[]) AS elem
          ) combined
          WHERE elem IS NOT NULL AND btrim(elem) <> ''
        ) deduped
      ),
      '[]'::jsonb
    ),
    true
  ),
  updated_at = now()
WHERE e.id = 15826;

